from typing import List, Optional

def longest(strings: List[str]) -> Optional[str]:
    if not strings:
        return None
    max_length = 0
    max_str = None
    for s in strings:
        current_length = len(s)
        if current_length > max_length:
            max_length = current_length
            max_str = s
    return max_str

